mapper.select:
WITH recent_documents AS ( SELECT d.document_id FROM tb_stock_document d WHERE d.company_id = #{companyId} AND d.document_status = 'COMPLETED' ORDER BY d.created_at DESC, d.document_id DESC LIMIT #{size} ), recent_inspection_times AS ( SELECT i.inspection_type, i.inspected_at FROM tb_inspection i WHERE i.company_id = #{companyId} GROUP BY i.inspection_type, i.inspected_at ORDER BY i.inspected_at DESC LIMIT #{size} ), recent_inspection_units AS ( SELECT DISTINCT i.unit_id FROM tb_inspection i INNER JOIN recent_inspection_times recent_time ON recent_time.inspection_type = i.inspection_type AND recent_time.inspected_at = i.inspected_at WHERE i.company_id = #{companyId} ), latest_inbound_documents AS ( SELECT ranked.unit_id, ranked.document_no FROM ( SELECT mu.unit_id, d.document_no, ROW_NUMBER() OVER ( PARTITION BY mu.unit_id ORDER BY d.created_at DESC, d.document_id DESC ) AS rn FROM recent_inspection_units recent_unit INNER JOIN tb_stock_movement_unit mu ON mu.unit_id = recent_unit.unit_id INNER JOIN tb_stock_movement m ON m.movement_id = mu.movement_id AND m.company_id = #{companyId} AND m.movement_type = 'INBOUND' AND m.canceled_movement_id IS NULL INNER JOIN tb_stock_document d ON d.company_id = m.company_id AND d.document_id = m.document_id ) ranked WHERE ranked.rn = 1 ) SELECT activity.type, activity.label, activity.document_no, activity.title, activity.quantity, activity.processed_at, activity.route FROM ( SELECT d.document_type AS type, CASE WHEN d.document_type = 'INBOUND' THEN '입고' ELSE '출고' END AS label, d.document_no, COALESCE( CONCAT( SUBSTRING_INDEX(GROUP_CONCAT(DISTINCT p.part_name ORDER BY m.movement_id SEPARATOR ','), ',', 1), CASE WHEN COUNT(DISTINCT m.movement_id) > 1 THEN CONCAT(' 외 ', COUNT(DISTINCT m.movement_id) - 1, '종') ELSE '' END ), '-' ) AS title, COALESCE(SUM(m.quantity), 0) AS quantity, d.created_at AS processed_at, CASE WHEN d.document_type = 'INBOUND' THEN 'inbound' ELSE 'outbound' END AS route FROM recent_documents recent_document INNER JOIN tb_stock_document d ON d.company_id = #{companyId} AND d.document_id = recent_document.document_id LEFT JOIN tb_stock_movement m ON m.company_id = d.company_id AND m.document_id = d.document_id AND m.canceled_movement_id IS NULL LEFT JOIN tb_pc_part p ON p.company_id = m.company_id AND p.part_id = m.part_id GROUP BY d.document_id, d.document_type, d.document_no, d.created_at
UNION ALL
SELECT inspection_activity.type, inspection_activity.label, inspection_activity.document_no, CONCAT( SUBSTRING_INDEX( GROUP_CONCAT(DISTINCT inspection_activity.part_title ORDER BY inspection_activity.part_id SEPARATOR ','), ',', 1 ), CASE WHEN COUNT(DISTINCT inspection_activity.part_id) > 1 THEN CONCAT(' 외 ', COUNT(DISTINCT inspection_activity.part_id) - 1, '종') ELSE '' END ) AS title, COUNT(*) AS quantity, inspection_activity.processed_at, inspection_activity.route FROM ( SELECT i.inspection_type AS type, CASE WHEN i.inspection_type = 'INITIAL' THEN '검수' WHEN i.inspection_type = 'CORRECTION' THEN '정정' ELSE '재검수' END AS label, COALESCE(inbound_document.document_no, '-') AS document_no, p.part_id, CONCAT(p.part_name, CASE WHEN p.model_name IS NOT NULL AND p.model_name != '' THEN CONCAT(' ', p.model_name) ELSE '' END) AS part_title, i.inspected_at AS processed_at, 'history/inspection' AS route FROM tb_inspection i INNER JOIN recent_inspection_times recent_time ON recent_time.inspection_type = i.inspection_type AND recent_time.inspected_at = i.inspected_at INNER JOIN tb_pc_part_unit u ON u.company_id = i.company_id AND u.unit_id = i.unit_id INNER JOIN tb_pc_part p ON p.company_id = u.company_id AND p.part_id = u.part_id LEFT JOIN latest_inbound_documents inbound_document ON inbound_document.unit_id = i.unit_id WHERE i.company_id = #{companyId} ) inspection_activity GROUP BY inspection_activity.type, inspection_activity.label, inspection_activity.document_no, inspection_activity.processed_at, inspection_activity.route ) activity ORDER BY activity.processed_at DESC LIMIT #{size}
